/*
* Calculate Total Premium Share on the reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let sharePercentage = this.YQP_SHARE_PERCENTAGE;
let totalPremium = this.YQP_TOTAL_PREMIUM_GRID;
totalPremium = parseFloat(totalPremium);
let forteOrder = this.YQP_FORTE_ORDER_GRID;
//Validate no empty values
if (sharePercentage != "" && totalPremium != "" && forteOrder != "" &&
    sharePercentage != null && totalPremium != null && forteOrder != null) {
    //Set percentages
    forteOrder = forteOrder / 100;
    sharePercentage = sharePercentage / 100;
    //Get total Forte order
    newTotalForteOrder = totalPremium * forteOrder;
    //Calc total and round Javascript without losses
    let totalPremiumShare = Math.round((newTotalForteOrder * sharePercentage + Number.EPSILON) * 100) / 100
    return totalPremiumShare;
} else {
    return "";
}

/*
* Calculate Broker deduction on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let totalPremium = this.YQP_TOTAL_PREMIUM_SHARE;
totalPremium = parseFloat(totalPremium);
let brokerPercentage = this.YQP_BROKER_DEDUCTION;
//Validate no empty values
if (brokerPercentage != "" && totalPremium != "") {
    //Get percentage
    brokerPercentage = brokerPercentage / 100;
    //Do it negative
    brokerPercentage = brokerPercentage * (-1);
    //Calc Broker deduction and round it with no losses
    let brokerDeductionUSD = Math.round((totalPremium * brokerPercentage + Number.EPSILON) * 100) / 100
    return brokerDeductionUSD;
} else {
    return 0;
}

/*
* Calculate Gross Share on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let totalPremium = this.YQP_TOTAL_PREMIUM_SHARE;
totalPremium = parseFloat(totalPremium);
let taxPercentage = this.YQP_TAX_ON_GROSS;
//Validate no empty values
if (taxPercentage != "" && totalPremium != "") {
    //Get percentage
    taxPercentage = taxPercentage / 100;
    //Do it negative
    taxPercentage = taxPercentage * (-1);
    //Calc Gross Share and round it with no losses
    let taxGrossShare = Math.round((totalPremium * taxPercentage + Number.EPSILON) * 100) / 100
    return taxGrossShare;
} else {
    return 0;
}

/*
* Calculate Broker Total Deduction on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let brokerDeduction = this.YQP_BROKER_DEDUCTION;
let totalPremium = this.YQP_TOTAL_PREMIUM_GRID;
//Validate no empty values
totalPremium = parseFloat(totalPremium);
if (brokerDeduction != "" && totalPremium != "" &&
    brokerDeduction != null && totalPremium != null) {
    //Get percentage
    brokerDeduction = brokerDeduction / 100;
    //Do it negative
    brokerDeduction = brokerDeduction * (-1);
    //Calc Broker Total deduction and round it with no losses
    let brokerDeductionTotal = Math.round((totalPremium * brokerDeduction + Number.EPSILON) * 100) / 100;
    return brokerDeductionTotal;
} else {
    return 0;
}

/*
* Calculate Net Technical Total on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let totalPremium = this.YQP_TOTAL_PREMIUM_GRID;
totalPremium = parseFloat(totalPremium);
let brokerDeductionTotal = this.YQP_BROKER_DEDUCTION_TOTAL;
//Validate no empty values
if (totalPremium != "" && totalPremium != null) {
    if (brokerDeductionTotal == "" || brokerDeductionTotal == null) {
        brokerDeductionTotal = 0;
    }
    //Calc Net Technical Total and round it with no losses
    let netTechnicalTotal = Math.round((totalPremium + brokerDeductionTotal + Number.EPSILON) * 100) / 100;
    return netTechnicalTotal;
} else {
    return 0;
}

/*
* Calculate Net Technical Share on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let totalPremiumShare = this.YQP_TOTAL_PREMIUM_SHARE;
let brokerDeductionShare = this.YQP_BROKER_DEDUCTION_USD;
//Validate no empty values
if (totalPremiumShare != "" && totalPremiumShare != null) {
    if (brokerDeductionShare == "" || brokerDeductionShare == null) {
        brokerDeductionShare = 0;
    }
    //Calc Net Technical Share and round it with no losses
    let netTechnicalShare = Math.round((totalPremiumShare + brokerDeductionShare + Number.EPSILON) * 100) / 100;
    return netTechnicalShare;
} else {
    return 0;
}

/*
* Calculate Total Premium Grid on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let totalPremium = this.YQP_TOTAL_PREMIUM_GRID;
//Validate no empty values
if (totalPremium != "" && totalPremium != null) {
    //Change it to String
    totalPremium = String(totalPremium);
    //Replace dot by comma
    totalPremium = totalPremium.replace(".", ",");
    return totalPremium;
} else {
    return "";
}

/*
* Calculate Tax Net share on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let netTechnicalPremium = this.YQP_NET_TECHNICAL_PREMIUM_SHARE;
netTechnicalPremium = parseFloat(netTechnicalPremium);
let taxPercentageNet = this.YQP_TAX_ON_NET;
//Validate no empty values
if (taxPercentageNet != "" && netTechnicalPremium != "") {
    //Get Percentage
    taxPercentageNet = taxPercentageNet / 100;
    //Do it negative
    taxPercentageNet = taxPercentageNet * (-1);
    //Calc the Tax net Share with no losses
    let taxNetShare = Math.round((netTechnicalPremium * taxPercentageNet + Number.EPSILON) * 100) / 100;
    return taxNetShare;
} else {
    return 0;
}

/*
* Calculate Premium Reserves Gross on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let totalPremium = this.YQP_TOTAL_PREMIUM_SHARE;
totalPremium = parseFloat(totalPremium);
let reservesGross = this.YQP_PREMIUM_RESERVES_ON_GROSS;
//Validate no empty values
if (reservesGross != "" && totalPremium != "") {
    //Get Percentage
    reservesGross = reservesGross / 100;
    //Do it negative
    reservesGross = reservesGross * (-1);
    //Calc the Premium Reserves Gross with no losses
    let premiumReserves = Math.round((totalPremium * reservesGross + Number.EPSILON) * 100) / 100;
    return premiumReserves;
} else {
    return 0;
}

/*
* Calculate Premium Reserves Net on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let totalPremium = this.YQP_TOTAL_PREMIUM_SHARE;
totalPremium = parseFloat(totalPremium);
let reservesNet = this.YQP_PREMIUM_RESERVES_ON_NET;
//Validate no empty values
if (reservesNet != "" && totalPremium != "") {
    //Get Percentage
    reservesNet = reservesNet / 100;
    //Do it negative
    reservesNet = reservesNet * (-1);
    //Calc the Premium Reserves Net with no losses
    let reservesNetShare = Math.round((totalPremium * reservesNet + Number.EPSILON) * 100) / 100;
    return reservesNetShare;
} else {
    return 0;
}

/*
* Calculate Forte fee on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let technicalPremium = this.YQP_NET_TECHNICAL_PREMIUM_SHARE;
technicalPremium = parseFloat(technicalPremium);
let forteFeePercentage = this.YQP_FORTE_FEE_PERCENTAGE;
//Validate no empty values
if (forteFeePercentage != "" && technicalPremium != "") {
    //Get Percentage
    forteFeePercentage = forteFeePercentage / 100;
    //Do it negative
    forteFeePercentage = forteFeePercentage * (-1);
    //Calc Forte Fee with no losses
    let forteFee = Math.round((technicalPremium * forteFeePercentage + Number.EPSILON) * 100) / 100;
    return forteFee;
} else {
    return 0;
}

/*
* Calculate Ceded Share on the Reinsurer record list
* by Ana Castillo
*/
//Parameters to calculate
let technicalPremium = this.YQP_NET_TECHNICAL_PREMIUM_SHARE;
technicalPremium = parseFloat(technicalPremium);
let taxGrossShare = this.YQP_TAX_GROSS_SHARE;
if (taxGrossShare == "NaN" || taxGrossShare == undefined) taxGrossShare = 0;
let taxNetShare = this.YQP_TAX_NET_SHARE;
if (taxNetShare == "NaN" || taxNetShare == undefined) taxNetShare = 0;
let reservesGrossShare = this.YQP_PREMIUM_RESERVES_GROSS_SHARE;
if (reservesGrossShare == "NaN" || reservesGrossShare == undefined) reservesGrossShare = 0;
let reservesNetShare = this.YQP_PREMIUM_RESERVES_NET_SHARE;
if (reservesNetShare == "NaN" || reservesNetShare == undefined) reservesNetShare = 0;
let forteFee = this.YQP_FORTE_FEE;
//Validate no empty values
if (technicalPremium != "" && forteFee != "" &&
    technicalPremium != null && forteFee != null) {
    //Sumatory of all values
    let cededShare = technicalPremium + taxGrossShare + taxNetShare + reservesGrossShare + reservesNetShare + forteFee;
    //Calc Ceded Share with no losses
    cededShare = Math.round((cededShare + Number.EPSILON) * 100) / 100;
    return cededShare;
} else {
    return 0;
}

/*
* Validate at least one row on record list (No rows-> NO, Rows filled-> YES)
* by Ana Castillo
*/
//No rows on the record list
if (this.YQP_REINSURER_INFORMATION == null) {
    return "NO";
} else {
    let reinsurerLength = this.YQP_REINSURER_INFORMATION.length;
    //Set Flag to validate Reinsurer rows
    let flagReinsurer = 0;
    for (let t = 0; t < reinsurerLength; t++) {
        //Validate if fields are no empty
        if (this.YQP_REINSURER_INFORMATION[t]["YQP_SHARE_PERCENTAGE"] != "" && this.YQP_REINSURER_INFORMATION[t]["YQP_SHARE_PERCENTAGE"] != null) {
            flagReinsurer = 1;
        }
    }
    if (flagReinsurer == 1) {
        return "YES";
    } else {
        return "NO";
    }
}

/*
* Validate Submit button to show or hide (Show -> YES, Hide -> NO)
* by Ana Castillo
* Modified by Helen Callisaya
* Modified by Cinthia Romero
* Modified by Ana Castillo
*/
var submitVariables = new Object();
submitVariables['YQP_SUBMIT_VISIBLE'] = "NO";
submitVariables['YQP_SUBMIT_100_MESSAGE'] = "NO";
submitVariables['YQP_SUBMIT_5_REINSURER_LIMIT'] = "NO";
submitVariables['YQP_SUBMIT_REINSURER_SIGNATURE'] = "NO";
//sum of the YQP_SHARE_PERCENTAGE field
let sumSharePercentage = 0;
let reinsurersSignatures = JSON.parse(this.PM_OPEN_REINSURERS_CONFIGURED_SIGN);
let auxSignature = "YES";
let auxReinsurerFail = "<ul style='color: red;'>";
if (this.YQP_REINSURER_INFORMATION != null && this.YQP_REINSURER_INFORMATION.length > 0) {
    let loopRequestLen = this.YQP_REINSURER_INFORMATION.length;
    for (let i = 0; i < loopRequestLen; i++) {
        sumSharePercentage = sumSharePercentage + this.YQP_REINSURER_INFORMATION[i]["YQP_SHARE_PERCENTAGE"];
    }

    //Validate if reinsurers selected has the signature configured on openl
    if (reinsurersSignatures != "") {
        for (let i = 0; i < loopRequestLen; i++) {
            if (reinsurersSignatures[this.YQP_REINSURER_INFORMATION[i]["YQP_REINSURER_NAME"]["LABEL"]] != "YES") {
                auxSignature = "NO";
                auxReinsurerFail += "<li>" + this.YQP_REINSURER_INFORMATION[i]["YQP_REINSURER_NAME"]["LABEL"] + "</li>";
            }
        }
    }
} else {
    submitVariables['YQP_SUBMIT_100_MESSAGE'] = "YES";
}
auxReinsurerFail += "</ul><p style='color: red;'>Reinsurer(s) has not a singature configured, please contact your system administrator or change of reinsurer.</p>";
submitVariables['YQP_SUBMIT_REINSURER_SIGNATURE'] = auxSignature;
submitVariables['YQP_SUBMIT_REINSURER_SIGNATURE_FAIL'] = auxReinsurerFail;

//Validates that the sum of YQP_SHARE_PERCENTAGE is equal to 100%
if (sumSharePercentage == 100) {
    submitVariables['YQP_SUBMIT_100_MESSAGE'] = "YES";
}
//Validate if reinsurer has more than 5 records
if (this.YQP_REINSURER_INFORMATION.length <= 5) {
    submitVariables['YQP_SUBMIT_5_REINSURER_LIMIT'] = "NO";
} else {
    submitVariables['YQP_SUBMIT_5_REINSURER_LIMIT'] = "YES";
}
//Validate submit button
if (this.YQP_VALIDATE_ONE_REINSURER == "YES" &&
    submitVariables['YQP_SUBMIT_100_MESSAGE'] == "YES" &&
    submitVariables['YQP_SUBMIT_5_REINSURER_LIMIT'] == "NO" &&
    submitVariables['YQP_SUBMIT_REINSURER_SIGNATURE'] == "YES") {
        submitVariables['YQP_SUBMIT_VISIBLE'] = "YES";
}

return submitVariables;

/*
* Calc Get the user id of the request 
* by Helen Callisaya
*/
return this._user.id;

/*
* Calc Show request error
* by Helen Callisaya
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERRORS.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == null || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

/*
* Calc Get the user fullname of the request 
* by Helen Callisaya
*/
return this._user.fullname;

